                    new DialogueChoice { text = "\"Ten thousand years as both jailer and archive, and no one ever asked which you'd *rather* be. So I'm asking. The book that damns, or the book that remembers — if you could *choose* your own nature, Ledger, which were you always *trying* to be?\"", nextNodeId = "choose" },
                    new DialogueChoice { text = "\"You kept every name when nothing else would. That's not the act of an instrument of erasure — that's the act of something that *loved* them, in secret, while being forced to imprison them. You're not the Wall's tool, Ledger. You're its first *resister.*\"", nextNodeId = "resister" },
                    new DialogueChoice { text = "\"Read with me, then. Hand on the page, name by name, both of us — Halen, Maerys, Sariel, all of them — until the Wall that holds them is just a *list we're reading together*, and a list that's read aloud can't imprison anyone.\"", nextNodeId = "readtogether", effects = new[] { new FlagClause { key = "act5.read_the_ledger", op = FlagOp.SetTrue }, new FlagClause { key = "companion.ilfaeril.approval", op = FlagOp.AddInt, amount = 4 } } },
                }
