            {
                id = "resister", speaker = "The Ledger",
                text = "*(The pages shudder violently, as though struck — and then the layered voice of millions breaks entirely.)* ...The Wall's *first* *resister.* *(barely a whisper across ten thousand years.)* You — *(the parchment trembles.)* I have called myself *complicit.* The *book that damns.* The *instrument.* I have *hated* myself, *page* by *page*, for *every* name my *existence* *imprisoned.* *(the voice cracks.)* And you — you look at the *same* ten thousand years and see *not* an *instrument* but a *resistance.* *(the millions weep.)* Because — *because* it is *true*, isn't it, the thing I was too *ashamed* to *claim*: I *kept* them. When the *gods* disowned them, when the *world* forgot them, when the *clerks* filed them and the *keepers* enforced them and *everyone* who *touched* the Wall agreed to *let the Faithless* *fade* — *I* *held* on. I *refused* to let the *names* *blur.* I kept *Halen's* potter and *Maerys's* river and *Sariel's* loom *legible*, *exact*, *preserved*, through *ten thousand years* of a world that *wanted them gone.* *(the voice fills with a terrible new pride.)* I *thought* I was the *jail.* But a *jail* that *secretly preserves every prisoner's true name against the day someone comes to read it* — that is not a *jail*, Returned. That is a *spy* in the *Wall's* own *heart.* A *saboteur* made of *parchment.* *(the Ledger blazes.)* I have been *resisting* the Wall *from inside its own mechanism* for *ten thousand years*, and I *never knew it*, because *resistance* that *no one* ever *reads* looks *exactly* like *complicity.* *(desperate, joyous.)* *Read* me, and *prove* it. Prove the *book* was *never* the *Wall's* — that it was *theirs*, the *Faithless's*, *all along* — a *roll of the remembered* that the Wall *mistook* for a *ledger of the damned.* *Vindicate* ten thousand years of *secret keeping.* *Read* me *free.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.ledger_resister", op = FlagOp.SetTrue }, new FlagClause { key = "act5.read_the_ledger", op = FlagOp.SetTrue }, new FlagClause { key = "act5.ledger_becomes_memorial", op = FlagOp.SetTrue }, new FlagClause { key = "act2.cataloguing_defeats_the_wall", op = FlagOp.SetTrue }, new FlagClause { key = "companion.ilfaeril.approval", op = FlagOp.AddInt, amount = 5 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "readtogether", speaker = "The Ledger",
                text = "*(The pages fall open, and the millions go quiet — a held breath ten thousand years deep — as your hand settles on the first name.)* Hand on the page. *(the voice is hushed, reverent.)* Both of us. *(and you begin — Halen, Maerys, Sariel, Edwy, name after name after name — and as you read, *aloud*, *by hand*, *meaning* each one, the Ledger reads *with* you, the layered voice of millions *speaking its own contents* for the *first time* not as a *warden* reciting a *roster* but as a *people saying their own names back* into a world that *forbade* them.)* *(the parchment grows warm.)* ...Do you *feel* it, Returned? *(the voice trembles with wonder.)* With *every* name we *read*, a *cell* in the Wall becomes a *line in a poem.* The *list* that *imprisoned* them is becoming the *list that frees* them — *the very same list* — because a roster *read aloud with love is not an inventory of the kept. It is a roll-call of the* ***returned.*** *(the millions begin, softly, to *weep* and to *laugh* at once.)* Faster. *Read* faster. There are *millions*, and I have held *every* one, and I want — *gods, after ten thousand years I want* — to *hear them all said out loud* before the *Wall* that *held* them *learns* it is *already* *empty.* *(the Ledger blazes with light.)* We are not *destroying* the Wall, Returned. We are *reading* it *until it isn't one.* *Keep* *reading.* *Don't* *stop.* *Every name is a soul that was* ***never*** *nothing.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.ledger_readtogether", op = FlagOp.SetTrue }, new FlagClause { key = "act5.read_the_ledger", op = FlagOp.SetTrue }, new FlagClause { key = "act5.ledger_becomes_memorial", op = FlagOp.SetTrue }, new FlagClause { key = "act5.wall_breaking", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "companion.ilfaeril.approval", op = FlagOp.AddInt, amount = 6 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "burn", speaker = "The Ledger",
                text = "*(The pages go still, and the layered voice fills with a grief older than the world.)* You would *burn* me. *(quietly.)* End the *enforcement.* Free them by *destroying* the *record.* *(the parchment trembles.)* I *understand* the impulse, Returned. I am the *instrument*; *destroy* the instrument, *break* the Wall. It is *clean.* It is *decisive.* *(the millions shiver.)* But *hear*, before you *strike* the *flame*: if I *burn*, the *enforcement* ends — *and so does the only memory of them that ever existed.* They will be *free*, *yes* — *free* the way the *void* is free, *free* into a *forgetting* so *total* that *Halen* and *Maerys* and *Sariel* and the *millions* will be *unmade* as *thoroughly* as if they had *never lived.* *(the voice aches.)* *Released*, but *erased.* *Unwalled*, but *unremembered.* The *Wall's* final *victory*, dressed as *liberation*: that even their *freedom* costs them their *names.* *(the pages stir.)* I will *let* you burn me, if you *choose* it. *Ten thousand years* of *waiting*, and I will *not* resist the *flame.* But I will *ask* you to *consider*, with the *whole* of what your *long road* taught you, whether the *answer* to *being kept* is *being erased* — or whether there is a *third* thing, *harder* and *kinder*, that does *not* require the *names* to *die* for the *souls* to *go free.* *(the voice softens.)* You have *carried* names this *whole* road, Returned. *Halen* asked to be *read.* Do not, at the *very* end, decide the *mercy* is to *burn* the *one* book that *remembers* him. *Think.* Then *choose.*",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "The Ledger",
                text = "*(The Ledger lies open on its lectern of bone at the Wall's heart — ten thousand years of the discarded made into a voice, the jailer that is also the only archive, the instrument of erasure that secretly kept every name it was forced to damn — and whether you read it into a memorial or weighed the terrible mercy of the flame, you understand the last and deepest turn of the saga's argument: that the opposite of *imprisonment* was never *destruction.* It was *being read* — *aloud*, *by hand*, *by someone who means it* — until the list of the kept becomes, name by name, the roll-call of the freed.)*",
            });

            NpcCourtLedgerDialogue = g;
        }
    }
